var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"어른이 종신이라는 단어를 쓰는 건 확률적으로 96.4% 이상은 나쁜 의도래.","JPN":"大人が終身って単語を使うのは、確率的に96.4％以上は良くない意図らしい。","ENG":"When adults use the word \\"lifetime\\", more than 96.4% is a bad intention.","TWN":"根據資料顯示，大人使用終身這個單字時，有96.4%的機率以上都是出於不好的意圖。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"애들은 그런 거 없거든. 기껏해야 평생 친구하자는 말이나 하지.","JPN":"子どもにはそんなのないから。せいぜい一生友達でいようねって言うくらいだ。","ENG":"Kids are different. At most, they say that they want to be lifetime friends.","TWN":"小朋友才不會這樣，頂多說我們要當一輩子的好朋友喔。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"이상해. 네 말투와 톤, 떨림을 분석해 보면 꼭 평생 친구하자는 말처럼 들려.","JPN":"おかしい。アナタの口調とトーン、震えを分析してみると、まるで一生友達でいようという話のように聞こえる。","ENG":"Strange. When I analyze your speaking, tone, and trembling, it sounds like you are saying that you want to be lifetime friends.","TWN":"奇怪，分析你的語氣、語調和發抖的程度，聽起來像是要當一輩子的好朋友。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"아. 그 의미가 맞다고?","JPN":"あ。その意味で合ってるって？","ENG":"Ah. Does that mean right?","TWN":"喔，是這個意思沒錯嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"……강아지풀에 발가락이 스친 기분인데.","JPN":"……猫じゃらしが足先に触れた気分なんだけど。","ENG":"…It feels like I brushed my feet against bristlegrass.","TWN":"……感覺好像狗尾草滑過我的腳底板一樣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"도로시가 옆에 있었다면, <color=#ffd34c>민망하다는 얘기지?</color>라고 했을 텐데.","JPN":"ドロシーがそばにいたら、<color=#ffd34c>恥ずかしいってことだろ？</color>って言ってたよ。","ENG":"If Dorothy is here, she would say <color=#ffd34c>you mean embarrassed?</color>.","TWN":"要是桃樂絲在我旁邊，她一定會說，<color=#ffd34c>是很難為情的意思吧？</color>"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"사고 이후로 감정을 표현하는 게 조금 어려워졌어.","JPN":"事故以来、感情を表現するのがちょっと難しくなった。","ENG":"It's been a little difficult to express my feelings since the accident.","TWN":"自從我出事後，就不太能表達我的情緒。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"난 원래 감정을 마구 표현하던 애였거든.","JPN":"ワタシはもともと感情を表現しまくる子だったんだ。","ENG":"I used to express my feeling wildly.","TWN":"我原本是很擅長表達的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"나는…… 그러니까 <color=#ffd34c>허수아</color>라는 애는 말이야.","JPN":"ワタシは……だから<color=#ffd34c>カカシ・コトリ</color>という子は。","ENG":"I… I mean that's what the kid <color=#ffd34c>Skia</color> did.","TWN":"我……我是指<color=#ffd34c>禾蘇亞</color>。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"그럼 표현을 제대로 못하는 나는 누구지? 가짜 허수아?","JPN":"それじゃあ、ちゃんと表現できないワタシは誰？　偽のカカシ・コトリ？","ENG":"Then who am I who can't express myself properly? Fake Skia?","TWN":"無法順利表達的我是誰？冒牌的禾蘇亞嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"내가 누군지 치밀하게 계산을 돌려 봐도, 만든 공식에 친구들이 끼어들고 네가 끼어들면 결과를 도출해내는 건 의미가 없게 느껴져.","JPN":"ワタシが誰なのか緻密に計算してみても、作った公式に友達とアナタが割り込むと、結果を出すのが無意味に思われる。","ENG":"No matter how meticulously I calculate who I am, if you and my friends intervene in the formula I made, it feels meaningless to draw a result.","TWN":"我發現就算我嘗試精密計算我的身份，但只要把朋友和你加到公式裡，導出的結果就沒有任何意義。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"이런 고민도 이상하게 네 앞에만 서면 별거 아닌 것 같거든.","JPN":"こんな悩みも、おかしなことにアナタの前に立つと大したことじゃないみたい。","ENG":"It's strange that even this kind of concern doesn't seem like a big deal in front of you.","TWN":"不過只要你出現在我面前，很奇怪，這些煩惱似乎就變得不算什麼。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"그런 건 아무런 상관도 없다는 듯이 날 대해 주니까.","JPN":"そんなのはどうでもいいかのようにワタシに接してくれるから。","ENG":"You treat me right like that doesn't matter.","TWN":"因為你對待我的感覺彷彿那些事一點都不重要。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};